class TrieNode:
    def __init__(self):
        self.children = {}
        self.is_word = False

class Trie:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word):
        node = self.root
        for char in word:
            if char not in node.children:
                node.children[char] = TrieNode()
            node = node.children[char]
        node.is_word = True

    def search(self, word):
        node = self.root
        for char in word:
            if char not in node.children:
                return False
            node = node.children[char]
        return node is not None and node.is_word

    def starts_with(self, prefix):
        node = self.root
        for char in prefix:
            if char not in node.children:
                return False
            node = node.children[char]
        return True

    def get_words_with_prefix(self, prefix):
        node = self.root
        for char in prefix:
            if char not in node.children:
                return []
            node = node.children[char]

        words = []
        self._collect_words(node, prefix, words)
        return words

    def _collect_words(self, node, current_word, words):
        if node.is_word:
            words.append(current_word)

        for char, child in node.children.items():
            self._collect_words(child, current_word + char, words)


if __name__ == '__main__':
    trie = Trie()
    trie.insert("apple")
    trie.insert("app")
    trie.insert("apricot")
    trie.insert("banana")

    print(trie.search("apple"))  # True
    print(trie.search("app"))  # True
    print(trie.search("ap"))   # False
    print(trie.starts_with("ap")) # True
    print(trie.starts_with("ba")) # True
    print(trie.starts_with("az")) # False

    print(trie.get_words_with_prefix("ap")) # ['apple', 'app', 'apricot']
    print(trie.get_words_with_prefix("b")) # ['banana']
    print(trie.get_words_with_prefix("z")) # []
